"use client";

import { useState, useTransition } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { AlertCircle, Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { SignInFormClient as SignInFormClientProps } from "@/types/global";

export function SignInFormClient({
  handleSubmit,
  signUpWithGoogle,
  signInWithGitHub,
}: SignInFormClientProps) {
  const [isPending, startTransition] = useTransition();
  const router = useRouter();
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const validateField = (name: string, value: string) => {
    let error = "";

    if (name === "email") {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!value || !emailRegex.test(value)) {
        error = "Please enter a valid email address";
      }
    }

    if (name === "password") {
      if (!value || value.length < 8) {
        error = "Password must be at least 8 characters";
      } else if (!/(?=.*[a-z])/.test(value)) {
        error = "Must contain lowercase letter";
      } else if (!/(?=.*[A-Z])/.test(value)) {
        error = "Must contain uppercase letter";
      } else if (!/(?=.*\d)/.test(value)) {
        error = "Must contain a number";
      }
    }

    return error;
  };

  const handleBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setTouched({ ...touched, [name]: true });
    const error = validateField(name, value);
    setErrors({ ...errors, [name]: error });
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    if (touched[name]) {
      const error = validateField(name, value);
      setErrors({ ...errors, [name]: error });
    }
  };

  const onSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    // Validate all fields
    const newErrors: Record<string, string> = {};
    const newTouched: Record<string, boolean> = {};

    ["email", "password"].forEach((field) => {
      const value = formData.get(field) as string;
      newTouched[field] = true;
      const error = validateField(field, value);
      if (error) newErrors[field] = error;
    });

    setTouched(newTouched);
    setErrors(newErrors);

    if (Object.keys(newErrors).length > 0) {
      return;
    }

    startTransition(async () => {
      const result = await handleSubmit(formData);
      if (result?.success) {
        router.push("/dashboard");
      }
      if (result?.errors) {
        setErrors(result.errors);
      }
    });
  };

  return (
    <>
      {errors.general && (
        <div className="p-3 rounded-lg bg-promptdoc-error/10 border border-promptdoc-error/20 flex items-start gap-2">
          <AlertCircle className="h-4 w-4 text-promptdoc-error mt-0.5 flex-shrink-0" />
          <p className="text-sm text-promptdoc-error font-medium">
            {errors.general}
          </p>
        </div>
      )}
      {/* GOOGLE SIGNIN BUTTON */}
      <form action={signUpWithGoogle}>
        <Button
          type="submit"
          variant="outline"
          className="w-full h-11 border-border bg-promptdoc-primary hover:bg-promptdoc-primary-hover text-white"
        >
          <svg className="mr-2 h-5 w-5" viewBox="0 0 24 24">
            <path
              fill="currentColor"
              d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
            />
            <path
              fill="currentColor"
              d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
            />
            <path
              fill="currentColor"
              d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
            />
            <path
              fill="currentColor"
              d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
            />
          </svg>
          Continue with Google
        </Button>
      </form>
      {/* GITHUB SIGNIN BUTTON */}
      <form action={signInWithGitHub}>
        <Button
          type="submit"
          variant="outline"
          className="w-full h-11 border-border bg-promptdoc-primary hover:bg-promptdoc-primary-hover text-white"
        >
          <svg className="mr-2 h-5 w-5" viewBox="0 0 24 24">
            <path
              fill="currentColor"
              d="M12 2C6.477 2 2 6.477 2 12c0 4.418 2.865 8.166 6.839 9.489.5.092.682-.217.682-.483 0-.237-.009-.868-.013-1.703-2.787.605-3.375-1.343-3.375-1.343-.455-1.155-1.11-1.463-1.11-1.463-.908-.62.
069-.608.069-.608 1.003.07 1.531 1.03 1.531 1.03.892 1.528 2.341 1.086
.291-.213.562-.85.212-1.67-.217-.163-.89-.58-.29-1.142.218-.162.708-.58 2.32.88.674-.188 1.39-.282 2.104-.285.713.003 1.43.097 2.096.285 1.612-1.46 2.32-.88 2.32-.88.36.562.134.98.104 1.142.082.457.3.94.218 1.142.
064.82.214 1.53.214 1.84 0 1.327-.01 2.394-.01 2.72 0 .268.18.58.688.48C19.138 20.164 22 16.418 22 12c0-5.523-4.477-10-10-10z"
            />
          </svg>
          Continue with GitHub
        </Button>
      </form>

      <div className="relative">
        <div className="absolute inset-0 flex items-center">
          <span className="w-full border-t border-border" />
        </div>
        <div className="relative flex justify-center text-xs uppercase">
          <span className="bg-card px-2 text-muted-foreground">
            Or continue with
          </span>
        </div>
      </div>
      {/* EMAIL AND PASSWORD FIELDS */}
      <form onSubmit={onSubmit} className="space-y-4">
        <div className="space-y-2">
          <Label
            htmlFor="email"
            className="text-sm font-medium text-card-foreground"
          >
            Email
          </Label>
          <Input
            id="email"
            type="email"
            placeholder="name@example.com"
            name="email"
            required
            disabled={isPending}
            onBlur={handleBlur}
            onChange={handleChange}
            className={`h-11 bg-background text-foreground placeholder:text-muted-foreground transition-colors ${
              errors.email && touched.email
                ? "border-promptdoc-error focus-visible:ring-promptdoc-error"
                : "border-border"
            }`}
          />
          {errors.email && touched.email && (
            <div className="flex items-center gap-1.5 text-promptdoc-error">
              <AlertCircle className="h-3.5 w-3.5" />
              <p className="text-xs">{errors.email}</p>
            </div>
          )}
        </div>
        <div className="space-y-2">
          <Label
            htmlFor="password"
            className="text-sm font-medium text-card-foreground"
          >
            Password
          </Label>
          <Input
            id="password"
            type="password"
            placeholder="Create a strong password"
            name="password"
            required
            disabled={isPending}
            onBlur={handleBlur}
            onChange={handleChange}
            className={`h-11 bg-background text-foreground placeholder:text-muted-foreground transition-colors ${
              errors.password && touched.password
                ? "border-promptdoc-error focus-visible:ring-promptdoc-error"
                : "border-border"
            }`}
          />
          {errors.password && touched.password && (
            <div className="flex items-center gap-1.5 text-promptdoc-error">
              <AlertCircle className="h-3.5 w-3.5" />
              <p className="text-xs">{errors.password}</p>
            </div>
          )}
          {!errors.password && (
            <p className="text-xs text-muted-foreground">
              8+ characters with uppercase, lowercase, and number
            </p>
          )}
        </div>
        <Button
          type="submit"
          disabled={isPending}
          className="w-full h-11 bg-primary text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
        >
          {isPending ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Logging in...
            </>
          ) : (
            "Sign In"
          )}
        </Button>{" "}
      </form>
    </>
  );
}
